class Solution {
    public long findMaximumNumber(long k, int x) {
        long num = 1;
        long accumulatedPrice = 0;
        while (true) {
            long price = calculatePrice(num, x);
            if (accumulatedPrice + price > k) {
                break;
            }
            accumulatedPrice += price;
            num++;
        }
        return num - 1;
    }

    private long calculatePrice(long num, int x) {
        long price = 0;
        long temp = num;
        long multiplier = 1;
        while (temp > 0) {
            if ((temp & 1) == 1 && (multiplier % x) == 0) {
                price++;
            }
            temp >>= 1;
            multiplier <<= 1;
        }
        return price;
    }
}
